var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"지하 주차장이라…… 그 영악한 놈이 퇴로도 없는 곳에 제 발로 기어 들어왔다는 건가?","JPN":"地下駐車場か……あのずる賢いやつが退路もないところにわざわざ入り込むだろうか？","ENG":"The basement parking lot… That manipulative bastard crawled in where there's no escape?","TWN":"地下停車場……那個狡猾的傢伙跑到沒有退路的地方嗎？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장, 레비아는? 아직도 무전이 안 돼?","JPN":"隊長、レヴィアは？　まだ無線繋がらない？","ENG":"Captain, where's Levia? She still not answering her comms?","TWN":"隊長，莉維亞呢？無線電還是不通嗎？"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"신참이 낙오되는 건 흔한 일이야, 이유리.","JPN":"新米が落伍するのはよくあることだ、カスカベ。","ENG":"It's natural for a rookie to fall behind, Lee Yuri.","TWN":"李悠麗，新人脫隊是常有的事。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"머리 좋은 녀석이니까 합류 지점으로 먼저 갔을 거다.","JPN":"頭のいいやつだから先に合流地点に向かったんだろう。","ENG":"She's smart, so I'm sure she's already on her way to the rendezvous point.","TWN":"不過她是個聰明人，應該會直接到集合地點。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"우리도 이쯤에서 물러나는 게 낫겠어.","JPN":"俺たちもここら辺で引いた方がいい。","ENG":"We should also be heading back about now.","TWN":"我們也先撤退到那吧！"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"총알로 박음질까지 다 해 뒀는데 포기하자고?","JPN":"銃弾で穴まで開けてやったのに諦めろっていうのか？","ENG":"You want to give up now?! After we already shredded him with bullets?","TWN":"我們好不容易打中他，你現在說要放棄？"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"방울뱀 코지는 돈 때문에 자기 부모 형제까지 죽인 후레자식이야.","JPN":"ガラガラヘビのコウジは金のために自分の親と兄弟まで殺した人でなしだ。","ENG":"That Rattlesnake Koji is a degenerate who killed his whole family for money.","TWN":"響尾蛇 戈帝可是個見錢眼開，為錢連自己的父母、兄弟姊妹都能殺的人渣。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"부상을 입어서 CRF 출력이 불안정한 지금이 기회야. 여기서 끝장을 내야 돼.","JPN":"怪我でCRFの出力が不安定な今がチャンスなんだ。ここでとどめを刺さないと。","ENG":"He's wounded. This is our chance to catch him while his CRF is still unstable.","TWN":"現在是好機會，趁他受傷CRF輸出不穩定，就在這裡解決掉他！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그래. 문제는 그 코지 놈이 자기 집안 재산을 꿀꺽했다는 거지.","JPN":"ああ。問題はそのコウジのやつが自分の家の全財産を丸呑みしてるってことだな。","ENG":"Sure. But the problem is that this Koji guy inherited all of his family's wealth.","TWN":"我知道，但問題是他侵吞家產，"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그리고 한 번 달아난 이상, 놈은 우리 모가지를 따려고 무슨 짓이든 할 수 있어.","JPN":"それに一度逃げ出した以上、やつは俺たちを殺すためには何でもする。","ENG":"And once he gets away, he might do everything in his power to kill us off one by one.","TWN":"加上被那傢伙給逃掉後，他不知道會使出什麼手段來取我們的項上人頭。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"주위를 살펴 봐. 매복하기에는 최적의 장소다.","JPN":"周りを見ろ。待ち伏せには打ってつけの場所だ。","ENG":"Check your surroundings. This is the perfect place for him to ambush us.","TWN":"你看看周圍，完全非常適合埋伏。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……거 봐. 말 꺼내기가 무섭게들 납셨군.","JPN":"……ほらな。言ったそばからお出ましだぞ。","ENG":"See? Speak of the devil.","TWN":"……你看，話才剛說完，就要這麼恐怖。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"전투화 발소리야. 용병들을 고용한 모양이네.","JPN":"戦闘靴の足音だ。傭兵を雇ったようだな。","ENG":"I hear footsteps. He must've hired mercenaries.","TWN":"從腳步聲聽起來像是軍靴，看來是有雇用傭兵。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이 개 같은 놈들! 너희들 민병대지?! 오늘 다 뒈진 목숨인 줄 알아!</color>","JPN":"<color=#ffd34c>このクソ野郎ども！　てめぇら民兵隊だろ！？　今日全員皆殺しにてやる！</color>","ENG":"<color=#ffd34c>You filthy mutts! You're the Militia, aren't you?! You're all gonna die tonight!</color>","TWN":"<color=#ffd34c>你們這些狗雜碎！民兵隊是吧？！我今天就讓你們全都變成死人！</color>"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>사내 놈들은 산 채로 공구리 쳐서 바다에 버려 주마! 계집년은 다리 몽둥이를 분질러다가……!</color>","JPN":"<color=#ffd34c>男どもは生きたままコンクリート詰めにして海に沈めてやるぜ！　女は足をへし折って……！</color>","ENG":"<color=#ffd34c>I'm gonna toss you boys to the fishes with cement shoes! And that chick's gonna have her legs snapped in two–!</color>","TWN":"<color=#ffd34c>那二個男的給我綁上石頭扔海裡！女的給我把腿打斷……！</color>"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"어지간히 선머슴 같았나 보군. 축하한다, 이유리.","JPN":"よっぽど男みたいに見えたんだな。おめでとう、カスカベ。","ENG":"You must've looked like a tomboy. Congrats, Yuri.","TWN":"他把你當成男的咧，恭喜囉，李悠麗。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};